import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface FraudNews {
  title: string;
  summary: string;
  sourceUrl: string;
  date: string;
}

export interface GameRound {
  id: string;
  content: string; // The message or call script
  type: 'sms' | 'call';
  isFraud: boolean;
  newsContext: string; // The news it was based on
  explanation: string; // Why it is/isn't fraud
}

export interface AppState {
  news: FraudNews[];
  collectedKeywords: string[];
  rounds: GameRound[];
  score: number;
  currentRoundIndex: number;
}

import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { FraudNews, GameRound } from "../types";

export const getAI = (customKey?: string) => {
  return new GoogleGenAI({ apiKey: customKey || (process.env.API_KEY as string) });
};

export async function fetchFraudNews(keywords: string[]): Promise<FraudNews[]> {
  const ai = getAI();
  const prompt = `Search for the latest fraud and scam news related to these keywords: ${keywords.join(", ")}. 
    Return a JSON array of objects with the following structure:
    - title: string
    - summary: a short summary of the fraud tactic
    - sourceUrl: URL of the news
    - date: string (approximate date)

    Translate the information to English if the source is in another language, but keep the core meaning.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              summary: { type: Type.STRING },
              sourceUrl: { type: Type.STRING },
              date: { type: Type.STRING },
            },
            required: ["title", "summary", "sourceUrl", "date"],
          },
        },
      },
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Error fetching news:", error);
    return [];
  }
}

export async function generateGameRounds(newsItems: FraudNews[]): Promise<GameRound[]> {
  const ai = getAI();
  const prompt = `Based on these real-world fraud news items, generate 5 game rounds for a simulation.
    For each round, create a realistic mockup of a message (SMS) or a phone call script.
    - Some rounds should be FAKE (scams based on the news).
    - Some rounds should be REAL (legitimate messages/calls for contrast).

    News Context: ${JSON.stringify(newsItems)}

    Return a JSON array of objects:
    - id: unique string
    - content: the text content of the message or call script
    - type: "sms" or "call"
    - isFraud: boolean
    - newsContext: title of the news item this is based on
    - explanation: short reason why this is or isn't a scam
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              content: { type: Type.STRING },
              type: { type: Type.STRING },
              isFraud: { type: Type.BOOLEAN },
              newsContext: { type: Type.STRING },
              explanation: { type: Type.STRING },
            },
            required: ["id", "content", "type", "isFraud", "newsContext", "explanation"],
          },
        },
      },
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Error generating rounds:", error);
    return [];
  }
}

export async function generateHighQualityImage(prompt: string, size: "1K" | "2K" | "4K"): Promise<string> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: size,
      },
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image data received");
}

export async function editImage(base64Image: string, editPrompt: string): Promise<string> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/png' } },
        { text: editPrompt },
      ],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image data received from edit");
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const variants = {
    primary: 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg shadow-indigo-500/30',
    secondary: 'bg-emerald-600 hover:bg-emerald-700 text-white shadow-lg shadow-emerald-500/30',
    danger: 'bg-rose-600 hover:bg-rose-700 text-white shadow-lg shadow-rose-500/30',
    ghost: 'bg-white/10 hover:bg-white/20 text-white',
  };

  return (
    <button
      className={`px-6 py-3 rounded-xl font-semibold transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 ${variants[variant]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      )}
      {children}
    </button>
  );
};

