import React, { useState } from 'react';
import { Button } from './Button';
import { fetchFraudNews } from '../services/geminiService';
import { FraudNews } from '../types';
import { Search, Globe, ShieldAlert, CheckCircle2 } from 'lucide-react';

interface Props {
  onNewsCollected: (news: FraudNews[]) => void;
}

export const CollectorAgent: React.FC<Props> = ({ onNewsCollected }) => {
  const [keywords, setKeywords] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [results, setResults] = useState<FraudNews[]>([]);

  const handleSearch = async () => {
    if (!keywords.trim()) return;
    setIsSearching(true);
    const keywordArray = keywords.split(',').map(k => k.trim());
    const news = await fetchFraudNews(keywordArray);
    setResults(news);
    onNewsCollected(news);
    setIsSearching(false);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-slide-in">
      <div className="text-center space-y-4">
        <h2 className="text-4xl font-bold bg-gradient-to-r from-indigo-400 to-emerald-400 bg-clip-text text-transparent">
          Intelligence Collector
        </h2>
        <p className="text-slate-400 max-w-lg mx-auto">
          Equip your agent with keywords. We'll scour the global web for the latest fraud techniques to train your simulator.
        </p>
      </div>

      <div className="glass-morphism p-8 rounded-3xl shadow-2xl">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 w-5 h-5" />
            <input
              type="text"
              value={keywords}
              onChange={(e) => setKeywords(e.target.value)}
              placeholder="e.g., crypto, phishing, bank impersonation..."
              className="w-full pl-12 pr-4 py-4 bg-slate-900/50 border border-slate-700 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-all"
            />
          </div>
          <Button 
            onClick={handleSearch} 
            isLoading={isSearching} 
            className="md:w-48"
          >
            Deploy Agent
          </Button>
        </div>
      </div>

      {results.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {results.map((item, idx) => (
            <div key={idx} className="glass-morphism p-6 rounded-2xl hover:scale-[1.02] transition-transform duration-300">
              <div className="flex items-start justify-between mb-3">
                <span className="bg-indigo-500/20 text-indigo-400 px-3 py-1 rounded-full text-xs font-medium border border-indigo-500/30">
                  Detected
                </span>
                <span className="text-slate-500 text-xs">{item.date}</span>
              </div>
              <h3 className="text-xl font-bold mb-2 text-white line-clamp-2">{item.title}</h3>
              <p className="text-slate-400 text-sm mb-4 line-clamp-3">{item.summary}</p>
              <div className="flex items-center justify-between mt-auto">
                <a 
                  href={item.sourceUrl} 
                  target="_blank" 
                  rel="noopener noreferrer" 
                  className="text-indigo-400 hover:text-indigo-300 text-sm flex items-center gap-1"
                >
                  <Globe className="w-4 h-4" /> Source
                </a>
                <CheckCircle2 className="text-emerald-500 w-5 h-5" />
              </div>
            </div>
          ))}
        </div>
      )}

      {results.length === 0 && !isSearching && keywords && (
        <div className="text-center p-12 glass-morphism rounded-3xl opacity-50">
          <ShieldAlert className="w-12 h-12 mx-auto text-slate-500 mb-4" />
          <p>Awaiting keywords for intelligence gathering...</p>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { PhoneFrame } from './PhoneFrame';
import { Button } from './Button';
import { GameRound, FraudNews } from '../types';
import { generateGameRounds } from '../services/geminiService';
import { Smartphone, ShieldCheck, ShieldAlert, Trophy, RotateCcw } from 'lucide-react';

interface Props {
  news: FraudNews[];
  onRestart: () => void;
}

export const SimulatorGame: React.FC<Props> = ({ news, onRestart }) => {
  const [rounds, setRounds] = useState<GameRound[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [score, setScore] = useState(0);
  const [feedback, setFeedback] = useState<{ correct: boolean; message: string } | null>(null);

  useEffect(() => {
    if (news.length > 0) {
      initGame();
    }
  }, [news]);

  const initGame = async () => {
    setIsGenerating(true);
    const generated = await generateGameRounds(news);
    setRounds(generated);
    setIsGenerating(false);
  };

  const handleGuess = (guess: boolean) => {
    const current = rounds[currentIndex];
    const correct = guess === current.isFraud;

    if (correct) setScore(s => s + 1);
    setFeedback({ correct, message: current.explanation });
  };

  const nextRound = () => {
    setFeedback(null);
    setCurrentIndex(i => i + 1);
  };

  if (isGenerating) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] space-y-6">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin"></div>
          <Smartphone className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-indigo-400 w-8 h-8" />
        </div>
        <p className="text-slate-400 animate-pulse font-medium">Crafting realistic simulations based on intelligence...</p>
      </div>
    );
  }

  if (currentIndex >= rounds.length && rounds.length > 0) {
    return (
      <div className="max-w-md mx-auto text-center space-y-8 animate-slide-in">
        <div className="relative p-1">
            <div className="absolute inset-0 bg-gradient-to-r from-indigo-500 to-emerald-500 blur-xl opacity-20"></div>
            <div className="relative glass-morphism p-12 rounded-3xl border-2 border-indigo-500/20">
              <Trophy className="w-20 h-20 text-yellow-500 mx-auto mb-6" />
              <h2 className="text-4xl font-black mb-2">TRAINING COMPLETE</h2>
              <div className="text-6xl font-black text-indigo-400 mb-4">{score} / {rounds.length}</div>
              <p className="text-slate-400 mb-8">
                {score === rounds.length ? "Untouchable! You are a fraud-fighting master." : "Good progress. Vigilance is a muscle that needs training."}
              </p>
              <Button onClick={onRestart} className="w-full">
                <RotateCcw className="w-5 h-5" /> Start New Deployment
              </Button>
            </div>
        </div>
      </div>
    );
  }

  const currentRound = rounds[currentIndex];

  return (
    <div className="flex flex-col md:flex-row items-center justify-center gap-12 p-4">
      <div className="flex-1 max-w-lg space-y-6 hidden md:block">
        <h2 className="text-5xl font-black italic tracking-tighter">THE GAUNTLET</h2>
        <p className="text-xl text-slate-400 leading-relaxed">
          Fraudsters move fast, just like traffic. Each message is a real-world scenario. Decipher if it's safe or a trap.
        </p>
        <div className="flex gap-4">
          <div className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 flex-1">
            <div className="text-slate-500 text-xs uppercase font-bold mb-1">Score</div>
            <div className="text-3xl font-black">{score}</div>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 flex-1">
            <div className="text-slate-500 text-xs uppercase font-bold mb-1">Round</div>
            <div className="text-3xl font-black">{currentIndex + 1} <span className="text-slate-600 text-lg">/ {rounds.length}</span></div>
          </div>
        </div>
      </div>

      <div className="relative group">
        <PhoneFrame>
          <div className="flex flex-col h-full">
            {/* Header info */}
            <div className="text-center py-4 border-b border-white/10 mb-6">
              <div className="w-12 h-12 bg-indigo-500/20 rounded-full mx-auto flex items-center justify-center mb-2">
                <Smartphone className="text-indigo-400 w-6 h-6" />
              </div>
              <div className="text-xs text-slate-500 font-bold uppercase tracking-widest">Incoming {currentRound?.type === 'sms' ? 'Message' : 'Call'}</div>
              <div className="text-sm font-semibold text-white">Unknown Sender</div>
            </div>

            {/* The "Moving" Content Card */}
            <div className="flex-1 relative overflow-hidden flex items-center justify-center">
              <div 
                className={`w-full glass-morphism p-6 rounded-2xl shadow-2xl transition-all duration-700 ease-in-out transform
                  ${feedback ? 'translate-x-[150%] opacity-0' : 'translate-x-0 opacity-100'}`}
              >
                <div className="bg-white/5 rounded-xl p-4 text-sm text-indigo-100 font-medium leading-relaxed italic border border-white/5">
                  "{currentRound?.content}"
                </div>
                <div className="mt-4 flex items-center gap-2 text-[10px] text-slate-500">
                  <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                  <span>LIVE SIMULATION ACTIVE</span>
                </div>
              </div>

              {feedback && (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-center animate-slide-in p-4">
                  {feedback.correct ? (
                    <ShieldCheck className="w-16 h-16 text-emerald-500 mb-4" />
                  ) : (
                    <ShieldAlert className="w-16 h-16 text-rose-500 mb-4" />
                  )}
                  <h3 className={`text-xl font-bold mb-2 ${feedback.correct ? 'text-emerald-400' : 'text-rose-400'}`}>
                    {feedback.correct ? "CORRECT IDENTIFICATION" : "SECURITY BREACH"}
                  </h3>
                  <p className="text-xs text-slate-400 leading-tight mb-6">{feedback.message}</p>
                  <Button onClick={nextRound} className="w-full text-xs py-2">Continue</Button>
                </div>
              )}
            </div>

            {/* Action Buttons - Sticky to bottom */}
            {!feedback && (
              <div className="grid grid-cols-2 gap-3 mt-6 pb-4">
                <button 
                  onClick={() => handleGuess(true)}
                  className="flex flex-col items-center gap-2 p-3 bg-rose-500/10 hover:bg-rose-500/20 border border-rose-500/30 rounded-2xl transition-all group"
                >
                  <ShieldAlert className="w-6 h-6 text-rose-500 group-hover:scale-110 transition-transform" />
                  <span className="text-[10px] font-black uppercase text-rose-400">FRAUD</span>
                </button>
                <button 
                  onClick={() => handleGuess(false)}
                  className="flex flex-col items-center gap-2 p-3 bg-emerald-500/10 hover:bg-emerald-500/20 border border-emerald-500/30 rounded-2xl transition-all group"
                >
                  <ShieldCheck className="w-6 h-6 text-emerald-500 group-hover:scale-110 transition-transform" />
                  <span className="text-[10px] font-black uppercase text-emerald-400">REAL</span>
                </button>
              </div>
            )}
          </div>
        </PhoneFrame>
        {/* Shadow decoration */}
        <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 w-48 h-4 bg-black/40 blur-xl rounded-full -z-10"></div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Button } from './Button';
import { generateHighQualityImage, editImage } from '../services/geminiService';
import { ImageIcon, Wand2, Download, Layers, Monitor, ChevronRight, AlertCircle } from 'lucide-react';

export const ImageStudio: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [editPrompt, setEditPrompt] = useState('');
  const [size, setSize] = useState<"1K" | "2K" | "4K">("1K");
  const [generatedImageUrl, setGeneratedImageUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [needsKey, setNeedsKey] = useState(false);

  const handleGenerate = async () => {
    if (!prompt) return;

    // Check for Pro API Key requirement
    const hasKey = await (window as any).aistudio?.hasSelectedApiKey();
    if (!hasKey) {
      setNeedsKey(true);
      return;
    }

    setIsGenerating(true);
    try {
      const url = await generateHighQualityImage(prompt, size);
      setGeneratedImageUrl(url);
    } catch (e: any) {
      if (e.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleEdit = async () => {
    if (!generatedImageUrl || !editPrompt) return;
    setIsEditing(true);
    try {
      const url = await editImage(generatedImageUrl, editPrompt);
      setGeneratedImageUrl(url);
      setEditPrompt('');
    } finally {
      setIsEditing(false);
    }
  };

  const openKeyDialog = async () => {
    await (window as any).aistudio?.openSelectKey();
    setNeedsKey(false);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-12 animate-slide-in p-6">
      <div className="flex flex-col lg:flex-row gap-12">
        {/* Controls Sidebar */}
        <div className="w-full lg:w-1/3 space-y-8">
          <div className="space-y-4">
            <h2 className="text-4xl font-black">AI IMAGE STUDIO</h2>
            <p className="text-slate-400">Powered by Gemini 3 Pro and 2.5 Flash Image. Professional grade visual generation.</p>
          </div>

          <div className="glass-morphism p-6 rounded-3xl space-y-6">
            <div className="space-y-4">
              <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                <Wand2 className="w-3 h-3" /> Initial Prompt
              </label>
              <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="A futuristic cyber-security interface with glowing neon circuits..."
                className="w-full h-32 p-4 bg-slate-900/50 border border-slate-700 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-sm"
              />
            </div>

            <div className="space-y-4">
              <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                <Monitor className="w-3 h-3" /> Resolution
              </label>
              <div className="grid grid-cols-3 gap-2">
                {(["1K", "2K", "4K"] as const).map((s) => (
                  <button
                    key={s}
                    onClick={() => setSize(s)}
                    className={`py-2 rounded-xl text-xs font-bold border transition-all ${
                      size === s 
                      ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg' 
                      : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:bg-slate-800'
                    }`}
                  >
                    {s}
                  </button>
                ))}
              </div>
            </div>

            {needsKey && (
              <div className="p-4 bg-amber-500/10 border border-amber-500/30 rounded-2xl flex items-start gap-3">
                <AlertCircle className="w-5 h-5 text-amber-500 shrink-0" />
                <div className="space-y-2">
                  <p className="text-xs text-amber-200">Gemini 3 Pro requires a personal API Key for high-res generation.</p>
                  <button 
                    onClick={openKeyDialog}
                    className="text-xs font-bold text-amber-500 underline"
                  >
                    Select Key Now
                  </button>
                </div>
              </div>
            )}

            <Button 
              onClick={handleGenerate} 
              isLoading={isGenerating} 
              className="w-full py-4"
            >
              Generate Masterpiece
            </Button>
          </div>
        </div>

