interface Props {
  news: FraudNews[];
  onRestart: () => void;
}

export const SimulatorGame: React.FC<Props> = ({ news, onRestart }) => {
  const [rounds, setRounds] = useState<GameRound[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [score, setScore] = useState(0);
  const [feedback, setFeedback] = useState<{ correct: boolean; message: string } | null>(null);
  const [isAnimating, setIsAnimating] = useState(false);

  useEffect(() => {
    if (news.length > 0) {
      initGame();
    }
  }, [news]);

  const initGame = async () => {
    setIsGenerating(true);
    const generated = await generateGameRounds(news);
    setRounds(generated);
    setIsGenerating(false);
  };

  const handleGuess = (guess: boolean) => {
    if (isAnimating) return;
    const current = rounds[currentIndex];
    const correct = guess === current.isFraud;

    if (correct) setScore(s => s + 1);
    setFeedback({ correct, message: current.explanation });
  };

  const nextRound = () => {
    setIsAnimating(true);
    setTimeout(() => {
      setFeedback(null);
      setCurrentIndex(i => i + 1);
      setIsAnimating(false);
    }, 800); // Matches car-zoom animation duration
  };

  if (isGenerating) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] space-y-6">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin"></div>
          <Smartphone className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-indigo-400 w-8 h-8" />
        </div>
        <p className="text-slate-400 animate-pulse font-medium">正在基于全球情报构建实战场景...</p>
      </div>
    );
  }

  if (currentIndex >= rounds.length && rounds.length > 0) {
    return (
      <div className="max-w-md mx-auto text-center space-y-8 animate-slide-in">
        <div className="relative p-1">
            <div className="absolute inset-0 bg-gradient-to-r from-indigo-500 to-emerald-500 blur-xl opacity-20"></div>
            <div className="relative glass-morphism p-12 rounded-[3rem] border-2 border-indigo-500/20">
              <Trophy className="w-20 h-20 text-yellow-500 mx-auto mb-6" />
              <h2 className="text-3xl font-black mb-2">演练结束</h2>
              <div className="text-6xl font-black text-indigo-400 mb-4">{score} / {rounds.length}</div>
              <p className="text-slate-400 mb-8">
                {score === rounds.length ? "无懈可击！你是当之无愧的反诈专家。" : "表现不错。请保持警惕，保护好个人隐私。"}
              </p>
              <Button onClick={onRestart} className="w-full">
                <RotateCcw className="w-5 h-5" /> 重新部署情报
              </Button>
            </div>
        </div>
      </div>
    );
  }

  const currentRound = rounds[currentIndex];

  return (
    <div className="flex flex-col md:flex-row items-center justify-center gap-12 p-4">
      <div className="flex-1 max-w-lg space-y-6 hidden md:block">
        <h2 className="text-5xl font-black tracking-tighter uppercase italic text-indigo-500">
          反诈模拟室
        </h2>
        <p className="text-xl text-slate-400 leading-relaxed">
          诈骗分子的手段瞬息万变，就像疾驰的赛车。你能通过蛛丝马迹识别出危险吗？
        </p>
        <div className="flex gap-4">
          <div className="glass-morphism p-6 rounded-[2rem] flex-1 border-white/5">
            <div className="text-slate-500 text-xs uppercase font-bold mb-1">当前得分</div>
            <div className="text-3xl font-black">{score}</div>
          </div>
          <div className="glass-morphism p-6 rounded-[2rem] flex-1 border-white/5">
            <div className="text-slate-500 text-xs uppercase font-bold mb-1">关卡</div>
            <div className="text-3xl font-black">{currentIndex + 1} <span className="text-slate-600 text-lg">/ {rounds.length}</span></div>
          </div>
        </div>
      </div>

      <div className="relative group">
        <PhoneFrame>
          <div className="flex flex-col h-full">
            {/* iOS Message Header */}
            <div className="bg-[#f2f2f7]/80 backdrop-blur-md sticky top-0 px-4 py-3 flex flex-col items-center border-b border-black/5 z-10">
              <div className="w-10 h-10 bg-gray-300 rounded-full flex items-center justify-center mb-1 overflow-hidden">
                <User className="text-gray-500 w-6 h-6" />
              </div>
              <div className="text-[11px] font-semibold text-gray-500 flex items-center gap-1">
                未知号码 <Info className="w-3 h-3" />
              </div>
            </div>

            {/* iMessage Stream Area */}
            <div className="flex-1 p-3 flex flex-col gap-4">
              <div className="text-center">
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                  {currentRound?.type === 'sms' ? '短信' : '来电提醒'} · 今天
                </span>
              </div>

              <div className={`flex flex-col gap-1 transition-all duration-700 ${isAnimating ? 'animate-car-zoom' : ''}`}>
                <div className="imessage-bubble imessage-received ios-shadow animate-slide-in">
                  {currentRound?.content}
