                </div>
              )}
            </div>

            {/* Action Buttons */}
            {!feedback && (
              <div className="px-4 pb-12 flex gap-4">
                <button 
                  onClick={() => handleGuess(true)}
                  className="flex-1 py-4 bg-rose-100 hover:bg-rose-200 text-rose-600 rounded-[2rem] font-black transition-all transform active:scale-95 border border-rose-200"
                >
                  <ShieldAlert className="w-5 h-5 mx-auto mb-1" />
                  诈骗信息
                </button>
                <button 
                  onClick={() => handleGuess(false)}
                  className="flex-1 py-4 bg-emerald-100 hover:bg-emerald-200 text-emerald-600 rounded-[2rem] font-black transition-all transform active:scale-95 border border-emerald-200"
                >
                  <ShieldCheck className="w-5 h-5 mx-auto mb-1" />
                  真实信息
                </button>
              </div>
            )}
          </div>
        </PhoneFrame>
        {/* Visual Shadow */}
