              <span className="text-[10px] font-black text-slate-500 tracking-widest uppercase">系统状态</span>
              <span className="text-xs font-bold text-white flex items-center gap-1">
                <Globe className="w-3 h-3 text-indigo-400" /> 已联网
              </span>
