        </p>
        <div className="flex gap-4">
          <div className="glass-morphism p-6 rounded-[2rem] flex-1 border-white/5">
            <div className="text-slate-500 text-xs uppercase font-bold mb-1">当前得分</div>
            <div className="text-3xl font-black">{score}</div>
          </div>
          <div className="glass-morphism p-6 rounded-[2rem] flex-1 border-white/5">
            <div className="text-slate-500 text-xs uppercase font-bold mb-1">关卡</div>
            <div className="text-3xl font-black">{currentIndex + 1} <span className="text-slate-600 text-lg">/ {rounds.length}</span></div>
          </div>
        </div>
      </div>

      <div className="relative group">
        <PhoneFrame>
          <div className="flex flex-col h-full">
            {/* iOS Message Header */}
            <div className="bg-[#f2f2f7]/80 backdrop-blur-md sticky top-0 px-4 py-3 flex flex-col items-center border-b border-black/5 z-10">
              <div className="w-10 h-10 bg-gray-300 rounded-full flex items-center justify-center mb-1 overflow-hidden">
