              <div className={`flex flex-col gap-1 transition-all duration-700 ${isAnimating ? 'animate-car-zoom' : ''}`}>
                <div className="imessage-bubble imessage-received ios-shadow animate-slide-in">
                  {currentRound?.content}
                </div>
              </div>

              {feedback && !isAnimating && (
                <div className="mt-8 flex flex-col items-center animate-slide-in px-4">
                  <div className={`w-14 h-14 rounded-full flex items-center justify-center mb-4 ${feedback.correct ? 'bg-emerald-500' : 'bg-rose-500'}`}>
